// Parse and Validate Request - V2
const body = $input.first().json.body;

console.log('📥 [WF06 V2.1] Request received:', JSON.stringify(body, null, 2));

// Validate required action field
if (!body.action) {
    throw new Error('Missing required field: action (must be "next_dates" or "available_slots")');
}

const validActions = ['next_dates', 'available_slots'];
if (!validActions.includes(body.action)) {
    throw new Error(`Invalid action: ${body.action}. Must be "next_dates" or "available_slots"`);
}

// Validate action-specific fields
if (body.action === 'next_dates') {
    // Default values
    const count = body.count || 3;
    const startDate = body.start_date || new Date().toISOString().split('T')[0];

    if (count < 1 || count > 10) {
        throw new Error('Invalid count: must be between 1 and 10');
    }

    console.log('✅ [WF06 V2.1] next_dates action validated:', { count, startDate });

    return {
        action: 'next_dates',
        count: count,
        start_date: startDate,
        service_type: body.service_type || 'energia_solar',
        duration_minutes: body.duration_minutes || 120
    };
}

if (body.action === 'available_slots') {
    if (!body.date) {
        throw new Error('Missing required field: date (format: YYYY-MM-DD)');
    }

    // Validate date format
    const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
    if (!dateRegex.test(body.date)) {
        throw new Error('Invalid date format. Use YYYY-MM-DD');
    }

    const duration = body.duration_minutes || 120;

    console.log('✅ [WF06 V2.1] available_slots action validated:', { date: body.date, duration });

    return {
        action: 'available_slots',
        date: body.date,
        duration_minutes: duration
    };
}

throw new Error('Unknown error in request parsing');

// Calculate Next N Business Days - V2
const data = $input.first().json;
const count = data.count;
const startDateStr = data.start_date;

console.log('📅 [WF06 V2.1] Calculating next business days:', { count, startDate: startDateStr });

// HARDCODED BUSINESS RULES (V7 pattern)
const WORK_DAYS = [1, 2, 3, 4, 5];  // Monday-Friday
const MAX_SEARCH_DAYS = 30;  // Search up to 30 days ahead

const startDate = new Date(startDateStr);
startDate.setHours(0, 0, 0, 0);

const businessDates = [];
let daysChecked = 0;

while (businessDates.length < count && daysChecked < MAX_SEARCH_DAYS) {
    const checkDate = new Date(startDate);
    checkDate.setDate(startDate.getDate() + daysChecked + 1);  // Start from tomorrow

    const dayOfWeek = checkDate.getDay();

    // Skip weekends (Sunday = 0, Saturday = 6)
    if (WORK_DAYS.includes(dayOfWeek)) {
        const dateStr = checkDate.toISOString().split('T')[0];

        businessDates.push({
            date: dateStr,
            day_of_week: dayOfWeek,
            iso_date: dateStr
        });

        console.log(`✅ [WF06 V2.1] Business day found: ${dateStr} (day ${dayOfWeek})`);
    }

    daysChecked++;
}

if (businessDates.length === 0) {
    throw new Error('No business days found in the next 30 days');
}

console.log(`✅ [WF06 V2.1] Found ${businessDates.length} business days`);

return {
    ...data,
    business_dates: businessDates,
    dates_to_check: businessDates.length
};

// Calculate Slot Availability for Multiple Dates - V2.1 INPUT FIX
// ===== FIX: Use correct node reference for input data =====
// PROBLEM: $input.first().json comes from "Get Calendar Events (Batch)" which is EMPTY
// SOLUTION: Use $node["Calculate Next Business Days"].json for business_dates and duration_minutes

const requestData = $node["Calculate Next Business Days"].json;
const businessDates = requestData.business_dates;
const durationMinutes = requestData.duration_minutes;

// ===== V2 FIX: ROBUST EMPTY CALENDAR HANDLING =====
// n8n behavior:
// - Empty calendar: [{ json: {} }] (1 item with empty object)
// - Calendar with events: [{ json: { id: "...", start: {...}, ... } }, ...]
// - API error: [] (no items)

const rawItems = $('Get Calendar Events (Batch)').all();

console.log(`🔍 [WF06 V2.1] Raw items from calendar API:`, {
    count: rawItems.length,
    first_item: rawItems.length > 0 ? JSON.stringify(rawItems[0].json) : 'NO_ITEMS'
});

// Filter out empty objects (check if .json has any meaningful properties)
const calendarEvents = rawItems
    .map(item => item.json)
    .filter(event => {
        // Empty object check: must have 'id' or 'start' property
        // Empty calendar returns: {}
        // Real event returns: { id: "...", start: { dateTime: "..." }, ... }
        const isRealEvent = event && (event.id || event.start);

        if (!isRealEvent && Object.keys(event || {}).length > 0) {
            console.log(`⚠️ [WF06 V2.1] Filtered out invalid event:`, event);
        }

        return isRealEvent;
    });

console.log(`📊 [WF06 V2.1] Processing ${businessDates.length} dates with ${calendarEvents.length} calendar events`);

// ⚠️ V2: Log empty calendar for debugging (this is NORMAL, not an error)
if (calendarEvents.length === 0) {
    console.log('ℹ️ [WF06 V2.1] Empty calendar detected - all slots will be available (no conflicts)');
}

// HARDCODED BUSINESS HOURS (V7 pattern)
const WORK_START = 8;   // 08:00
const WORK_END = 18;    // 18:00
const SLOT_INTERVAL = 60;  // 1-hour intervals

// Helper: Check if slot conflicts with any event
function hasConflict(slotStart, slotEnd, events) {
    for (const event of events) {
        // V2: Extra safety check (should never trigger after filter above)
        if (!event.start || !event.start.dateTime) {
            console.warn(`⚠️ [WF06 V2.1] Invalid event in hasConflict:`, event);
            continue;
        }

        const eventStart = new Date(event.start.dateTime);
        const eventEnd = new Date(event.end.dateTime);

        // Check overlap: slot starts before event ends AND slot ends after event starts
        if (slotStart < eventEnd && slotEnd > eventStart) {
            return true;  // Conflict found
        }
    }
    return false;  // No conflict
}

// Helper: Calculate all slots for a specific date
function calculateSlotsForDate(dateStr, events) {
    const allSlots = [];

    // Generate all possible slots
    for (let hour = WORK_START; hour < WORK_END; hour += (SLOT_INTERVAL / 60)) {
        const startTime = `${String(hour).padStart(2, '0')}:00`;
        const endHour = hour + (durationMinutes / 60);

        // Check if slot + duration fits in business hours
        if (endHour <= WORK_END) {
            const endTime = `${String(endHour).padStart(2, '0')}:00`;

            // Build ISO datetime strings with Brazil timezone
            const slotStart = new Date(`${dateStr}T${startTime}:00-03:00`);
            const slotEnd = new Date(`${dateStr}T${endTime}:00-03:00`);

            // Check for conflicts
            if (!hasConflict(slotStart, slotEnd, events)) {
                allSlots.push({
                    start_time: startTime,
                    end_time: endTime
                });
            }
        }
    }

    return allSlots;
}

// Process each business date
const datesWithAvailability = businessDates.map(dateInfo => {
    const availableSlots = calculateSlotsForDate(dateInfo.date, calendarEvents);

    console.log(`📆 [WF06 V2.1] ${dateInfo.date}: ${availableSlots.length} slots available`);

    return {
        date: dateInfo.date,
        day_of_week: dateInfo.day_of_week,
        total_slots: availableSlots.length,
        slots: availableSlots
    };
});

// Filter dates with at least 1 available slot
const validDates = datesWithAvailability.filter(d => d.total_slots > 0);

if (validDates.length === 0) {
    console.log('⚠️ [WF06 V2.1] No dates with available slots found');
}

console.log(`✅ [WF06 V2.1] ${validDates.length} dates with availability`);

return {
    dates_with_availability: validDates,
    total_dates_checked: businessDates.length,
    total_dates_available: validDates.length
};

// Format next_dates Response - V2
const data = $input.first().json;
const datesWithAvailability = data.dates_with_availability;

console.log('📤 [WF06 V2.1] Formatting next_dates response');

// Day of week names in Portuguese
const dayNames = {
    0: 'Domingo',
    1: 'Segunda',
    2: 'Terça',
    3: 'Quarta',
    4: 'Quinta',
    5: 'Sexta',
    6: 'Sábado'
};

// Helper: Format date display (DD/MM format)
function formatDateDisplay(dateStr) {
    const [year, month, day] = dateStr.split('-');
    return `${day}/${month}`;
}

// Helper: Get friendly date label (Amanhã, Depois de amanhã, etc)
function getFriendlyDateLabel(dateStr) {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const targetDate = new Date(dateStr);
    targetDate.setHours(0, 0, 0, 0);

    const diffDays = Math.floor((targetDate - today) / (1000 * 60 * 60 * 24));

    if (diffDays === 1) return 'Amanhã';
    if (diffDays === 2) return 'Depois de amanhã';

    return formatDateDisplay(dateStr);
}

// Helper: Quality indicator based on slot count
function getQualityIndicator(totalSlots) {
    if (totalSlots >= 5) return 'high';
    if (totalSlots >= 3) return 'medium';
    return 'low';
}

// Format dates for response
const formattedDates = datesWithAvailability.map(dateInfo => {
    const friendlyLabel = getFriendlyDateLabel(dateInfo.date);
    const dayName = dayNames[dateInfo.day_of_week] || 'Dia';
    const display = `${friendlyLabel} (${formatDateDisplay(dateInfo.date)})`;

    return {
        date: dateInfo.date,
        display: display,
        day_of_week: dayName,
        total_slots: dateInfo.total_slots,
        quality: getQualityIndicator(dateInfo.total_slots),
        slots: dateInfo.slots  // Include slots for debugging (optional)
    };
});

const response = {
    success: true,
    action: 'next_dates',
    dates: formattedDates,
    total_available: formattedDates.length
};

console.log('✅ [WF06 V2.1] Response formatted:', JSON.stringify(response, null, 2));

return response;

// Calculate Available Slots for Single Date - V2.1 INPUT FIX
// ===== FIX: Use correct node reference for input data =====
// PROBLEM: $input.first().json comes from "Get Calendar Events (Single Date)" which may be EMPTY
// SOLUTION: Use $node["Route by Action"].json for date and duration_minutes

const requestData = $node["Route by Action"].json;
const dateStr = requestData.date;
const durationMinutes = requestData.duration_minutes;

// ===== V2 FIX: ROBUST EMPTY CALENDAR HANDLING =====
const rawItems = $('Get Calendar Events (Single Date)').all();

console.log(`🔍 [WF06 V2.1] Raw items from calendar API (single date):`, {
    count: rawItems.length,
    first_item: rawItems.length > 0 ? JSON.stringify(rawItems[0].json) : 'NO_ITEMS'
});

// Filter out empty objects (same logic as batch path)
const calendarEvents = rawItems
    .map(item => item.json)
    .filter(event => event && (event.id || event.start));

console.log(`📊 [WF06 V2.1] Calculating slots for ${dateStr} with ${calendarEvents.length} events`);

if (calendarEvents.length === 0) {
    console.log('ℹ️ [WF06 V2.1] Empty calendar for this date - all slots available');
}

// HARDCODED BUSINESS HOURS (V7 pattern)
const WORK_START = 8;   // 08:00
const WORK_END = 18;    // 18:00
const SLOT_INTERVAL = 60;  // 1-hour intervals

// Helper: Format time range for display
function formatTimeRange(startTime, endTime) {
    const startHour = parseInt(startTime.split(':')[0]);
    const endHour = parseInt(endTime.split(':')[0]);

    // Convert to Portuguese format (9h, meio-dia, etc)
    const formatHour = (hour) => {
        if (hour === 12) return 'meio-dia';
        return `${hour}h`;
    };

    return `${formatHour(startHour)} às ${formatHour(endHour)}`;
}

// Helper: Check if slot conflicts with any event
function hasConflict(slotStart, slotEnd, events) {
    for (const event of events) {
        if (!event.start || !event.start.dateTime) {
            console.warn(`⚠️ [WF06 V2.1] Invalid event in hasConflict:`, event);
            continue;
        }

        const eventStart = new Date(event.start.dateTime);
        const eventEnd = new Date(event.end.dateTime);

        // Check overlap
        if (slotStart < eventEnd && slotEnd > eventStart) {
            return true;
        }
    }
    return false;
}

// Generate all possible slots
const availableSlots = [];

for (let hour = WORK_START; hour < WORK_END; hour += (SLOT_INTERVAL / 60)) {
    const startTime = `${String(hour).padStart(2, '0')}:00`;
    const endHour = hour + (durationMinutes / 60);

    // Check if slot + duration fits in business hours
    if (endHour <= WORK_END) {
        const endTime = `${String(endHour).padStart(2, '0')}:00`;

        // Build ISO datetime strings with Brazil timezone
        const slotStart = new Date(`${dateStr}T${startTime}:00-03:00`);
        const slotEnd = new Date(`${dateStr}T${endTime}:00-03:00`);

        // Check for conflicts
        if (!hasConflict(slotStart, slotEnd, calendarEvents)) {
            availableSlots.push({
                start_time: startTime,
                end_time: endTime,
                formatted: formatTimeRange(startTime, endTime)
            });

            console.log(`✅ [WF06 V2.1] Available: ${startTime}-${endTime}`);
        } else {
            console.log(`❌ [WF06 V2.1] Occupied: ${startTime}-${endTime}`);
        }
    }
}

console.log(`✅ [WF06 V2.1] ${availableSlots.length} slots available for ${dateStr}`);

return {
    date: dateStr,
    available_slots: availableSlots,
    total_available: availableSlots.length
};

// Format available_slots Response - V2
const data = $input.first().json;

console.log('📤 [WF06 V2.1] Formatting available_slots response');

const response = {
    success: true,
    action: 'available_slots',
    date: data.date,
    available_slots: data.available_slots,
    total_available: data.total_available
};

console.log('✅ [WF06 V2.1] Response formatted:', JSON.stringify(response, null, 2));

return response;
